#!/bin/bash\n# RAG Memory System API Test Script\n# Run this after setting up the demo data to test all API endpoints\n\nBASE_URL=\"http://localhost:3000\"\nSTORE_ID=\"YOUR_STORE_ID_HERE\"  # Replace with actual store ID from demo\nTOKEN=\"YOUR_JWT_TOKEN_HERE\"    # Replace with actual JWT token\n\necho \"🧪 RAG Memory System API Test Suite\"\necho \"====================================\"\necho \"\"\n\n# Test 1: Get Memory Health\necho \"1️⃣  Testing Memory Health...\"\ncurl -s -X GET \"$BASE_URL/memory/health/$STORE_ID\" \\\n  -H \"Authorization: Bearer $TOKEN\" | jq .\necho \"\"\n\n# Test 2: Get RAG Recommendations\necho \"2️⃣  Testing RAG Recommendations...\"\ncurl -s -X GET \"$BASE_URL/memory/recommendations/$STORE_ID\" \\\n  -H \"Authorization: Bearer $TOKEN\" | jq .\necho \"\"\n\n# Test 3: Get Sales Expansion Guidance\necho \"3️⃣  Testing Sales Expansion...\"\ncurl -s -X GET \"$BASE_URL/memory/expansion/$STORE_ID\" \\\n  -H \"Authorization: Bearer $TOKEN\" | jq .\necho \"\"\n\n# Test 4: Get Product Experience\necho \"4️⃣  Testing Product Experience...\"\ncurl -s -X GET \"$BASE_URL/memory/products/$STORE_ID?products=Milk,Bread,Tea\" \\\n  -H \"Authorization: Bearer $TOKEN\" | jq .\necho \"\"\n\n# Test 5: Get Product Relationships\necho \"5️⃣  Testing Product Relationships...\"\ncurl -s -X GET \"$BASE_URL/memory/relationships/$STORE_ID?minStrength=0.3\" \\\n  -H \"Authorization: Bearer $TOKEN\" | jq .\necho \"\"\n\n# Test 6: Get Experience Insights\necho \"6️⃣  Testing Experience Insights...\"\ncurl -s -X GET \"$BASE_URL/memory/insights/$STORE_ID\" \\\n  -H \"Authorization: Bearer $TOKEN\" | jq .\necho \"\"\n\n# Test 7: Manual Learning Trigger\necho \"7️⃣  Testing Manual Learning...\"\ncurl -s -X POST \"$BASE_URL/memory/learn/$STORE_ID\" \\\n  -H \"Authorization: Bearer $TOKEN\" \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"days\": 30}' | jq .\necho \"\"\n\necho \"✅ API Test Suite Completed!\"\necho \"\"\necho \"📝 Notes:\"\necho \"- Replace STORE_ID and TOKEN with actual values\"\necho \"- Make sure the server is running on localhost:3000\"\necho \"- Run the demo script first to create sample data\"